import React, { useState, useEffect, useRef } from 'react';
import { X, Plus, Maximize2, Minimize2 } from 'lucide-react';

export default function Terminal() {
  const [sessions, setSessions] = useState([]);
  const [activeSessionId, setActiveSessionId] = useState(null);
  const [devices, setDevices] = useState([]);
  const [showDeviceList, setShowDeviceList] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const terminalRef = useRef(null);
  const inputRef = useRef(null);

  // Carregar dispositivos
  useEffect(() => {
    fetch('/devices/api/list/')
      .then(res => res.json())
      .then(data => {
        const list = data.devices || data || [];
        setDevices(list.map(d => ({
          id: d.id,
          name: d.hostname || d.name,
          ip: d.ip_address || d.ip,
          vendor: d.vendor || 'linux',
          username: d.username || 'admin',
          port: d.port || 22
        })));
      })
      .catch(() => setDevices([]));
  }, []);

  // Scroll automatico
  useEffect(() => {
    if (terminalRef.current) {
      terminalRef.current.scrollTop = terminalRef.current.scrollHeight;
    }
  }, [sessions]);

  const activeSession = sessions.find(s => s.id === activeSessionId);

  // Conectar ao dispositivo via WebSocket
  const connectToDevice = (device) => {
    const sessionId = 'session-' + Date.now();

    // Determinar URL do WebSocket
    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
    const wsUrl = protocol + '//' + window.location.host + '/ws/ssh/';

    const ws = new WebSocket(wsUrl);

    const newSession = {
      id: sessionId,
      device: device,
      output: ['Conectando a ' + device.name + ' (' + device.ip + ')...', ''],
      ws: ws,
      status: 'connecting'
    };

    ws.onopen = () => {
      // Enviar comando de conexao
      ws.send(JSON.stringify({
        type: 'connect',
        device_id: device.id
      }));

      setSessions(prev => prev.map(s => 
        s.id === sessionId ? { ...s, status: 'connected' } : s
      ));
    };

    ws.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        const message = data.message || data.data || '';

        setSessions(prev => prev.map(s => {
          if (s.id === sessionId) {
            return { ...s, output: [...s.output, message] };
          }
          return s;
        }));
      } catch (e) {
        // Se nao for JSON, mostrar como texto
        setSessions(prev => prev.map(s => {
          if (s.id === sessionId) {
            return { ...s, output: [...s.output, event.data] };
          }
          return s;
        }));
      }
    };

    ws.onerror = (error) => {
      setSessions(prev => prev.map(s => {
        if (s.id === sessionId) {
          return { 
            ...s, 
            status: 'error',
            output: [...s.output, 'Erro de conexao WebSocket', '']
          };
        }
        return s;
      }));
    };

    ws.onclose = () => {
      setSessions(prev => prev.map(s => {
        if (s.id === sessionId) {
          return { 
            ...s, 
            status: 'disconnected',
            output: [...s.output, 'Conexao fechada', '']
          };
        }
        return s;
      }));
    };

    setSessions(prev => [...prev, newSession]);
    setActiveSessionId(sessionId);
    setShowDeviceList(false);
  };

  // Enviar caractere para o SSH
  const sendChar = (char) => {
    if (activeSession && activeSession.ws && activeSession.ws.readyState === WebSocket.OPEN) {
      activeSession.ws.send(JSON.stringify({ data: char }));
    }
  };

  // Handler de teclas
  const handleKeyDown = (e) => {
    // IMPORTANTE: Prevenir TAB de sair do terminal
    if (e.key === 'Tab') {
      e.preventDefault();
      e.stopPropagation();
      sendChar('\t');
      return false;
    }

    // Enter
    if (e.key === 'Enter') {
      e.preventDefault();
      sendChar('\r');
      return false;
    }

    // Backspace
    if (e.key === 'Backspace') {
      e.preventDefault();
      sendChar('\x7f');
      return false;
    }

    // Ctrl+C
    if (e.key === 'c' && e.ctrlKey) {
      e.preventDefault();
      sendChar('\x03');
      return false;
    }

    // Ctrl+D
    if (e.key === 'd' && e.ctrlKey) {
      e.preventDefault();
      sendChar('\x04');
      return false;
    }

    // Setas
    if (e.key === 'ArrowUp') {
      e.preventDefault();
      sendChar('\x1b[A');
      return false;
    }
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      sendChar('\x1b[B');
      return false;
    }
    if (e.key === 'ArrowRight') {
      e.preventDefault();
      sendChar('\x1b[C');
      return false;
    }
    if (e.key === 'ArrowLeft') {
      e.preventDefault();
      sendChar('\x1b[D');
      return false;
    }

    // Caractere normal
    if (e.key.length === 1) {
      e.preventDefault();
      sendChar(e.key);
      return false;
    }
  };

  // Fechar sessao
  const closeSession = (sessionId) => {
    const session = sessions.find(s => s.id === sessionId);
    if (session && session.ws) {
      session.ws.close();
    }
    setSessions(prev => prev.filter(s => s.id !== sessionId));
    if (activeSessionId === sessionId) {
      const remaining = sessions.filter(s => s.id !== sessionId);
      setActiveSessionId(remaining.length > 0 ? remaining[0].id : null);
    }
  };

  return (
    <div className={'h-full flex flex-col' + (isFullscreen ? ' fixed inset-0 z-50 bg-black' : '')}>
      {/* Header */}
      <div className="flex items-center justify-between bg-gray-800 border-b border-gray-700 px-4 py-3">
        <div className="flex items-center gap-3">
          <h1 className="text-xl font-bold text-white">Terminal SSH</h1>
          <button
            onClick={() => setShowDeviceList(!showDeviceList)}
            className="flex items-center gap-2 px-3 py-1.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
          >
            <Plus className="w-4 h-4" /> Nova Conexao
          </button>
        </div>
        <button
          onClick={() => setIsFullscreen(!isFullscreen)}
          className="p-2 rounded-lg hover:bg-gray-700 text-gray-300"
        >
          {isFullscreen ? <Minimize2 className="w-5 h-5" /> : <Maximize2 className="w-5 h-5" />}
        </button>
      </div>

      {/* Device List */}
      {showDeviceList && (
        <div className="absolute top-16 left-4 z-50 bg-gray-800 border border-gray-700 rounded-lg shadow-xl p-4 w-80">
          <h3 className="font-semibold mb-3 text-white">Selecione um dispositivo</h3>
          <div className="space-y-2 max-h-64 overflow-auto">
            {devices.length === 0 ? (
              <p className="text-gray-400 text-sm">Nenhum dispositivo cadastrado</p>
            ) : (
              devices.map(device => (
                <button
                  key={device.id}
                  onClick={() => connectToDevice(device)}
                  className="w-full flex items-center gap-3 p-2 rounded-lg hover:bg-gray-700 text-left"
                >
                  <div className={'w-2 h-2 rounded-full ' + 
                    (device.vendor === 'huawei' ? 'bg-red-500' :
                     device.vendor === 'mikrotik' ? 'bg-green-500' :
                     device.vendor === 'cisco' ? 'bg-blue-500' : 'bg-yellow-500')}
                  />
                  <div>
                    <div className="font-medium text-white">{device.name}</div>
                    <div className="text-xs text-gray-400">{device.ip} ({device.vendor})</div>
                  </div>
                </button>
              ))
            )}
          </div>
        </div>
      )}

      {/* Session Tabs */}
      {sessions.length > 0 && (
        <div className="flex bg-gray-900 border-b border-gray-700 overflow-x-auto">
          {sessions.map(session => (
            <div
              key={session.id}
              onClick={() => setActiveSessionId(session.id)}
              className={'flex items-center gap-2 px-4 py-2 border-r border-gray-700 cursor-pointer ' +
                (activeSessionId === session.id ? 'bg-gray-800' : 'hover:bg-gray-800')}
            >
              <div className={'w-2 h-2 rounded-full ' +
                (session.status === 'connected' ? 'bg-green-500' :
                 session.status === 'connecting' ? 'bg-yellow-500 animate-pulse' :
                 session.status === 'error' ? 'bg-red-500' : 'bg-gray-500')}
              />
              <span className="text-sm text-gray-200">{session.device.name}</span>
              <button
                onClick={(e) => { e.stopPropagation(); closeSession(session.id); }}
                className="p-0.5 rounded hover:bg-red-500/30 text-gray-400"
              >
                <X className="w-3 h-3" />
              </button>
            </div>
          ))}
        </div>
      )}

      {/* Terminal Output */}
      <div
        ref={terminalRef}
        className="flex-1 bg-black text-gray-100 font-mono text-sm overflow-auto p-4"
        onClick={() => inputRef.current?.focus()}
      >
        {sessions.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-gray-500">
            <p className="text-lg">Nenhuma sessao ativa</p>
            <p className="text-sm">Clique em "Nova Conexao" para iniciar</p>
          </div>
        ) : activeSession ? (
          <pre className="whitespace-pre-wrap break-all">
            {activeSession.output.join('')}
            <input
              ref={inputRef}
              type="text"
              className="opacity-0 absolute"
              onKeyDown={handleKeyDown}
              autoFocus
              autoComplete="off"
              autoCapitalize="off"
              spellCheck="false"
            />
          </pre>
        ) : null}
      </div>

      {/* Status Bar */}
      {activeSession && (
        <div className="flex items-center justify-between bg-gray-800 border-t border-gray-700 px-4 py-1.5 text-xs text-gray-400">
          <div className="flex items-center gap-4">
            <span className="flex items-center gap-1.5">
              <div className={'w-2 h-2 rounded-full ' +
                (activeSession.status === 'connected' ? 'bg-green-500' :
                 activeSession.status === 'connecting' ? 'bg-yellow-500' : 'bg-red-500')}
              />
              {activeSession.status === 'connected' ? 'Conectado' :
               activeSession.status === 'connecting' ? 'Conectando...' : 'Desconectado'}
            </span>
            <span>{activeSession.device.name} ({activeSession.device.ip})</span>
          </div>
          <span>TAB: autocompletar | Ctrl+C: cancelar | Ctrl+D: logout</span>
        </div>
      )}
    </div>
  );
}
